import React, { useState } from "react";
import "./Sidebar.css";

const Sidebar = () => {
    const [openSections, setOpenSections] = useState({});
    const [activeItem, setActiveItem] = useState("");
    const [isSidebarOpen, setIsSidebarOpen] = useState(true); // ← yeni state

    const menuGroups = [
        {
            title: "SİPARİŞ İŞLEMLERİ",
            items: ["Sipariş Oluştur", "Teslim Noktaları"],
        },
        {
            title: "GELİR & GİDER",
            items: ["Gelir Ekleme", "Gider Ekleme", "Eskalasyon Hesabı"],
        },
        {
            title: "RAPORLAR",
            items: ["Tedarik Analiz"],
        },
    ];

    const toggleSection = (title) => {
        setOpenSections((prev) => ({
            ...prev,
            [title]: !prev[title],
        }));
    };

    const toggleSidebar = () => {
        setIsSidebarOpen(!isSidebarOpen);
    };

    return (
        <aside className={`sidebar ${isSidebarOpen ? "open" : "closed"}`}>
            <button className="sidebar-toggle" onClick={toggleSidebar}>
                {isSidebarOpen ? "«" : "»"}
            </button>

            {isSidebarOpen &&
                menuGroups.map((group) => (
                    <div key={group.title} className="menu-group">
                        <div
                            className="menu-title expandable"
                            onClick={() => toggleSection(group.title)}
                        >
                            {group.title}
                            <span className="arrow">
                                {openSections[group.title] ? "▾" : "▸"}
                            </span>
                        </div>

                        {openSections[group.title] && (
                            <ul>
                                {group.items.map((item) => (
                                    <li
                                        key={item}
                                        className={activeItem === item ? "active" : ""}
                                        onClick={() => setActiveItem(item)}
                                    >
                                        {item}
                                    </li>
                                ))}
                            </ul>
                        )}
                    </div>
                ))}
        </aside>
    );
};

export default Sidebar;
